import { iconLoaders, IconLoader } from '../generated/icon-loaders';

const customLoaders = new Map<string, IconLoader>();

const normalizeName = (name: string | null | undefined): string | null => {
  if (!name) {
    return null;
  }

  return name.trim().toLowerCase();
};

export const registerIconLoader = (name: string, loader: IconLoader): void => {
  const normalized = normalizeName(name);
  if (!normalized || typeof loader !== 'function') {
    return;
  }
  customLoaders.set(normalized, loader);
};

export const unregisterIconLoader = (name: string): void => {
  const normalized = normalizeName(name);
  if (!normalized) {
    return;
  }
  customLoaders.delete(normalized);
};

export const clearIconLoaders = (): void => {
  customLoaders.clear();
};

export const getRegisteredIconNames = (): string[] => {
  return Array.from(new Set([...Object.keys(iconLoaders), ...customLoaders.keys()]));
};

export const resolveIconLoader = (name: string): IconLoader | undefined => {
  const normalized = normalizeName(name);
  if (!normalized) {
    return undefined;
  }

  return customLoaders.get(normalized) ?? iconLoaders[normalized];
};

export const loadIconContent = async (name: string): Promise<string | undefined> => {
  const loader = resolveIconLoader(name);
  if (!loader) {
    return undefined;
  }

  return loader();
};
